  "core_rules": {
    "treatment_algorithm": [
      "1) Pilih titik kausal sesuai kelainan meridian/organ.",
      "2) Tambahkan titik simptomatik sesuai lokasi keluhan tubuh (jika ada).",
      "3) Terapkan aturan Wu Xing: defisiensi -> tonifikasi titik Ibu; ekses -> sedasi titik Anak.",
      "4) Tambah titik pribadi / extra / 3 dewa / dominan bila perlu."
    ],
