      ],
      "Shu-Stream": [
        "Bi syndrome, nyeri terutama karena Damp"
      ],
      "Jing-River": [
        "untuk kondisi pada sinews/bones (yin within yang) dan perubahan suara"
      ],
      "He-Sea": [
        "untuk disorder Fu / lambung-usus / counterflow Qi"
      ]
