      "organ": ["Liver"],
      "unsur_wuxing": "Wood",
      "tipe": "defisiensi_xue",
      "gejala_kunci": [
        "pusing",
        "baal atau kesemutan ekstremitas",
        "insomnia",
        "penglihatan kabur/floaters",
        "rambut & kulit kering",
        "menstruasi sedikit/amenorrhea",
        "kram otot, kuku rapuh"
      ],
      "lidah": ["pucat", "tipis", "sedikit kering"],
      "nadi": ["choppy atau fine"],
      "prinsip_terapi": ["tonifikasi Liver", "nourish Blood"],
      "titik_utama": ["LR8", "SP6", "ST36", "CV4", "BL18", "BL20", "BL23", "BL17", "Yuyao(ex)"]
