        "tidak suka ditekan"
      ],
      "lidah": ["sabur putih"],
      "nadi": ["deep-wiry (terutama posisi rear)"],
      "prinsip_terapi": ["lancarkan Qi", "urai stagnasi di SI/Liver"]
